import{_ as s,o as e,c as i,a2 as t}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"虚拟内存、Page、Stack、Heap 与上下文切换","description":"","frontmatter":{},"headers":[],"relativePath":"05-backend-data/notes/05-linux-network/05-virtual-memory-pages-stack-heap-switch.md","filePath":"05-backend-data/notes/05-linux-network/05-virtual-memory-pages-stack-heap-switch.md","lastUpdated":null}'),n={name:"05-backend-data/notes/05-linux-network/05-virtual-memory-pages-stack-heap-switch.md"};function l(p,a,r,h,o,d){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="虚拟内存、page、stack、heap-与上下文切换" tabindex="-1">虚拟内存、Page、Stack、Heap 与上下文切换 <a class="header-anchor" href="#虚拟内存、page、stack、heap-与上下文切换" aria-label="Permalink to &quot;虚拟内存、Page、Stack、Heap 与上下文切换&quot;">​</a></h1><p>虚拟内存把进程使用的地址与物理存储解耦；page 是映射、保护和回收的基本粒度；stack 与 heap 是地址空间中的不同用途区域；上下文切换让有限 CPU 执行多个任务。</p><h2 id="_1-虚拟地址空间" tabindex="-1">1. 虚拟地址空间 <a class="header-anchor" href="#_1-虚拟地址空间" aria-label="Permalink to &quot;1. 虚拟地址空间&quot;">​</a></h2><p>程序读写的是虚拟地址。CPU 的内存管理单元根据页表把虚拟页转换为物理页，并检查读、写、执行和用户/内核权限。每个进程通常看到独立地址空间，同一个虚拟地址在不同进程中可映射到不同物理页。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V1[&quot;虚拟页 A&quot;] --&gt;|&quot;页表映射&quot;| P7[&quot;物理页 7&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V2[&quot;虚拟页 B&quot;] --&gt;|&quot;尚未驻留&quot;| F[&quot;文件或 swap&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V3[&quot;虚拟页 C&quot;] --&gt;|&quot;共享映射&quot;| P9[&quot;物理页 9&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V4[&quot;无有效映射&quot;] --&gt; S[&quot;触发访问错误&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>地址空间可包含程序代码、只读数据、动态链接库、匿名映射、文件映射、heap、各线程 stack 和内核保留区域。布局受架构、加载器、ASLR、运行时与配置影响，不应依赖固定地址。</p><p>虚拟空间大不表示物理占用大。程序可保留地址范围而暂未提交物理页；共享库也可被多个进程映射到相同物理页。</p><h2 id="_2-page、页表与-tlb" tabindex="-1">2. Page、页表与 TLB <a class="header-anchor" href="#_2-page、页表与-tlb" aria-label="Permalink to &quot;2. Page、页表与 TLB&quot;">​</a></h2><p>page size 是系统属性，常见基础页为 4 KiB，但不能硬编码。Linux 查询方式：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getconf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PAGESIZE</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getconf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PAGE_SIZE</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>页表按页保存映射和权限。每次都遍历多级页表成本高，CPU 用 TLB 缓存近期地址转换。切换地址空间、映射变化或工作集超过 TLB 容量会增加转换开销；具体是否刷新、是否保留条目依赖架构和 PCID/ASID 等机制。</p><p>大页可降低页表与 TLB 压力，但会增加内部碎片、分配和回收复杂度。HugeTLB 是显式预留的大页机制；Transparent Huge Pages 由内核尝试合并/拆分。是否启用应由真实延迟、内存和 workload 测试决定。</p><h2 id="_3-page-fault-与-demand-paging" tabindex="-1">3. Page fault 与 demand paging <a class="header-anchor" href="#_3-page-fault-与-demand-paging" aria-label="Permalink to &quot;3. Page fault 与 demand paging&quot;">​</a></h2><p>CPU 访问无当前有效转换或权限不匹配的地址时触发 page fault。内核可能：建立已有页的映射、分配零页、从文件读取、执行 copy-on-write，或向进程发送 <code>SIGSEGV</code>/<code>SIGBUS</code>。</p><ul><li>minor fault 不需从存储读取目标页，例如首次匿名分配或页已在 page cache。</li><li>major fault 需要可能阻塞的存储 I/O，通常成本更高。</li><li>copy-on-write fault 在写共享只读页时复制物理页，常出现在 fork 后。</li></ul><p>“fault”不自动表示程序错误；demand paging 正常依赖 fault。诊断要看速率、major/minor 分类、延迟与业务阶段。</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pid,min_flt,maj_flt,rss,vsz,cmd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/bin/time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./program</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>procps 字段和 GNU time 在 macOS 上不兼容。macOS 可用 <code>vm_stat</code>、Activity Monitor/Instruments 和系统自带 <code>/usr/bin/time -l</code>。</p><h2 id="_4-匿名内存、文件映射与-page-cache" tabindex="-1">4. 匿名内存、文件映射与 page cache <a class="header-anchor" href="#_4-匿名内存、文件映射与-page-cache" aria-label="Permalink to &quot;4. 匿名内存、文件映射与 page cache&quot;">​</a></h2><p>匿名映射没有直接后备文件，常承载 heap、stack 和运行时对象；内存压力下可留在 RAM 或写入 swap。文件映射把文件区间映射到地址空间，读写通过 page cache 与文件系统协调。</p><p>page cache 保存文件页以减少重复存储 I/O。脏页是内存中已修改但尚未持久化的文件页，最终由回写或显式同步处理。<code>write</code> 返回只表示数据交给内核，不必然已到稳定存储；持久化协议需正确使用 <code>fsync</code>/<code>fdatasync</code>，并考虑目录项和存储设备保证。</p><p>共享映射 <code>MAP_SHARED</code> 的修改可对其他映射者可见并回写文件；私有映射 <code>MAP_PRIVATE</code> 的写入通常通过 copy-on-write 保持进程私有。映射可见性不等于线程同步，仍需内存顺序和应用协议。</p><h2 id="_5-stack" tabindex="-1">5. Stack <a class="header-anchor" href="#_5-stack" aria-label="Permalink to &quot;5. Stack&quot;">​</a></h2><p>每个线程通常有自己的用户 stack，保存调用帧、返回地址、保存的寄存器和部分局部变量。编译器可把变量放寄存器、stack 或 heap，源码声明位置不决定最终存储。</p><p>stack 常有有限保留范围和 guard page。无限递归、过大栈上对象或线程过多可导致 stack overflow 或地址空间/物理内存压力。<code>ulimit -s</code> 显示 shell 为新进程设置的栈资源限制，但语言运行时可使用动态增长栈或自管策略。</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ulimit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;^Threads|^Vm(Stk|Data|RSS|Size)&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/proc/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/status&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>多个线程的栈不能只看进程 <code>VmStk</code> 就准确求和；需要结合 <code>/proc/PID/task/TID/maps</code>、运行时指标和实际 RSS。</p><h2 id="_6-heap-与分配器" tabindex="-1">6. Heap 与分配器 <a class="header-anchor" href="#_6-heap-与分配器" aria-label="Permalink to &quot;6. Heap 与分配器&quot;">​</a></h2><p>heap 是动态分配对象使用的区域概念，不一定是单一连续区间。C 分配器可通过 <code>brk</code> 与 <code>mmap</code> 从内核取得较大区域，再在用户态切分；Go、Java 等运行时有自己的 arena、size class 和垃圾回收。</p><p>应用“释放对象”不保证 RSS 立即下降：分配器可能保留页供复用；页可能尚未归还内核；碎片让已释放空间夹在活对象之间。内存泄漏应定义为不可再需要却仍被引用或资源未释放，不能只凭 RSS 上升断言。</p><p>内存指标边界：</p><table tabindex="0"><thead><tr><th>指标</th><th>表示</th><th>常见误读</th></tr></thead><tbody><tr><td>VSZ/VmSize</td><td>虚拟地址范围</td><td>当成实际 RAM</td></tr><tr><td>RSS/VmRSS</td><td>当前驻留页近似量</td><td>当成独占内存或活对象总量</td></tr><tr><td>PSS</td><td>共享页按映射者分摊</td><td>当成内核精确计费</td></tr><tr><td>anonymous</td><td>非文件后备页</td><td>全部当成业务 heap</td></tr><tr><td>swap</td><td>被换出的页</td><td>只要非零就认定正在抖动</td></tr></tbody></table><h2 id="_7-查看进程映射" tabindex="-1">7. 查看进程映射 <a class="header-anchor" href="#_7-查看进程映射" aria-label="Permalink to &quot;7. 查看进程映射&quot;">​</a></h2><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1,40p&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/proc/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/maps&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/proc/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/smaps_rollup&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pmap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>maps</code> 显示地址区间、权限、文件偏移、设备、inode 和路径；<code>rwxp</code> 中 <code>p</code> 表示私有、<code>s</code> 表示共享。<code>[heap]</code>、<code>[stack]</code> 只是内核标注的一部分，现代分配器的大块匿名 mmap 不一定都标作 <code>[heap]</code>。</p><p><code>smaps</code> 逐映射统计，读取大进程会有成本；<code>smaps_rollup</code> 给聚合值。<code>Pss</code>、<code>Private_Dirty</code>、<code>Shared_Clean</code> 等有助区分共享库与私有脏内存，但采样时状态仍会变化。</p><h2 id="_8-上下文切换" tabindex="-1">8. 上下文切换 <a class="header-anchor" href="#_8-上下文切换" aria-label="Permalink to &quot;8. 上下文切换&quot;">​</a></h2><p>调度器切出一个线程时保存其执行上下文，切入另一个线程时恢复。进程间切换还涉及不同地址空间；线程切换即使共享地址空间，也会改变寄存器、栈和工作集。</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ctxt|processes|procs_running|procs_blocked&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/stat</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pidstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>cswch/s</code> 是自愿切换，常由等待；<code>nvcswch/s</code> 是非自愿切换，常由抢占。数量必须除以吞吐或工作量并与基线比较。减少切换不是独立目标；忙等能让切换下降却浪费 CPU。</p><h2 id="_9-cgroup-与容器内存视角" tabindex="-1">9. cgroup 与容器内存视角 <a class="header-anchor" href="#_9-cgroup-与容器内存视角" aria-label="Permalink to &quot;9. cgroup 与容器内存视角&quot;">​</a></h2><p>容器进程仍使用宿主内核，但 cgroup 可限制可用内存。宿主 <code>MemAvailable</code> 很高时，容器也可因 <code>memory.max</code> 被 OOM kill。使用 cgroup v2 时：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/memory.current</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/memory.stat</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/memory.events</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/memory.max</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><code>memory.current</code> 是该 cgroup 及后代当前总内存；<code>memory.stat</code> 分类 anon、file、kernel 等；<code>memory.events</code> 的 <code>high</code>、<code>max</code>、<code>oom</code>、<code>oom_kill</code> 是累计事件。路径可能因容器运行时和 cgroup 层级不同，不能假设进程总在根路径。</p><h2 id="_10-完整案例-容器周期性被-oom-kill" tabindex="-1">10. 完整案例：容器周期性被 OOM kill <a class="header-anchor" href="#_10-完整案例-容器周期性被-oom-kill" aria-label="Permalink to &quot;10. 完整案例：容器周期性被 OOM kill&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>宿主有 32 GiB RAM 且 available 充足。</li><li>API 容器限制 512 MiB，每小时重启一次。</li><li>重启前 RSS 从 250 MiB 升到约 480 MiB；请求量同期增长。</li></ul><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li>读取 <code>memory.max</code> 确认 512 MiB，而不是依据宿主 free。</li><li>对 <code>memory.events</code> 前后取差，确认 <code>oom_kill</code> 增加。</li><li>查看 <code>memory.stat</code>，发现 anon 增长，file 稳定，排除 page cache 为主的假设。</li><li>采集语言运行时 heap profile，按对象类型发现无界请求结果缓存。</li><li>以固定 1000 个不同 key 重放，缓存条目与 heap 可稳定复现线性增长。</li><li>改为带容量和过期的缓存，并给队列设置上限；限制保留安全余量。</li></ol><h3 id="输出与验证" tabindex="-1">输出与验证 <a class="header-anchor" href="#输出与验证" aria-label="Permalink to &quot;输出与验证&quot;">​</a></h3><p>相同重放下缓存达到上限后内存进入平台期，<code>memory.events</code> 不再新增 <code>oom</code>/<code>oom_kill</code>，p99 和命中率符合目标。连续运行超过旧故障周期并比较 PSS、运行时 heap 与 cgroup current。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若 cgroup current 增长但运行时 heap 稳定，检查 mmap、线程 stack、native/cgo、文件页和内核内存；不要仅增大 GC 频率。若只有 <code>high</code> 增加而没有 kill，说明发生节流/回收压力，仍需结合延迟。提高 limit 只能作为有容量验证的缓解，不能替代有界设计。</p><h2 id="_11-常见错误" tabindex="-1">11. 常见错误 <a class="header-anchor" href="#_11-常见错误" aria-label="Permalink to &quot;11. 常见错误&quot;">​</a></h2><ul><li>把 VSZ 直接当内存泄漏。</li><li>把所有 page fault 当异常，或把 minor 和 major 成本混为一谈。</li><li>认为变量写在函数里就必然位于 stack。</li><li>认为 <code>free()</code>/GC 后 RSS 必须立刻下降。</li><li>只看宿主内存，不看 cgroup 限制和事件。</li><li>为降低上下文切换改成忙等，却不检查 CPU 与延迟。</li></ul><h2 id="_12-练习与完成标准" tabindex="-1">12. 练习与完成标准 <a class="header-anchor" href="#_12-练习与完成标准" aria-label="Permalink to &quot;12. 练习与完成标准&quot;">​</a></h2><ol><li>查询本机 page size，比较 <code>/proc/PID/maps</code>、<code>smaps_rollup</code> 与运行时 heap 指标。</li><li>运行一个逐页触碰匿名内存的测试，记录触碰前后 minor fault 与 RSS；限制最大分配，不能逼近系统容量。</li><li>比较 sleep 循环和 busy loop 的 CPU、切换与吞吐。</li><li>完成标准：能区分虚拟/驻留、匿名/文件、stack/heap、fault/非法访问，并用两类指标定位容器 OOM。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://docs.kernel.org/admin-guide/mm/concepts.html" target="_blank" rel="noreferrer">Linux Kernel：Memory Management Concepts</a>（访问日期：2026-07-17）</li><li><a href="https://docs.kernel.org/mm/process_addrs.html" target="_blank" rel="noreferrer">Linux Kernel：Process Addresses</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man5/proc_pid_smaps.5.html" target="_blank" rel="noreferrer">Linux man-pages：proc_pid_maps(5)、proc_pid_smaps(5)</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man2/mmap.2.html" target="_blank" rel="noreferrer">Linux man-pages：mmap(2)、madvise(2)</a>（访问日期：2026-07-17）</li><li><a href="https://docs.kernel.org/admin-guide/cgroup-v2.html#memory" target="_blank" rel="noreferrer">Linux Kernel：cgroup v2 memory controller</a>（访问日期：2026-07-17）</li></ul>`,59)])])}const u=s(n,[["render",l]]);export{k as __pageData,u as default};
